import React from 'react';
import { useNavigate } from 'react-router-dom';
import ProfileForm from '../components/ProfileForm';
import RiskForm from '../components/RiskForm';
import CalorieUpload from '../components/CalorieUpload';
import ProgressChart from '../components/ProgressChart';
import NutrientWarning from '../components/NutrientWarning';


// NOTE: Dashboard now receives the fetchProfile function from App.jsx,
// eliminating the need for local loading state/useEffect hooks.
const Dashboard = ({ profile, setProfile, fetchProfile }) => {
    
    const navigate = useNavigate();
    
    // Check for essential data needed for BMI/BMR/Risk Calculation
    const isProfileIncomplete = !profile.age || !profile.height || !profile.weight;

    return (
        <div className="container mx-auto">
            <h2 className="text-2xl font-semibold mb-6">Welcome, {profile.name || 'User'}!</h2>
            
            {/* Action Bar */}
            <div className="flex justify-end mb-6">
                <button 
                    onClick={() => navigate('/recommendations')}
                    className="bg-green-600 text-white px-6 py-2 rounded-lg shadow-md hover:bg-green-700 transition"
                >
                    View Personalized Plans 🧠
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                
                {/* 1. User Profile & Update (Module 1) */}
                <div className="md:col-span-1 bg-white p-6 rounded-lg shadow-lg">
                    <h3 className="text-xl font-bold mb-4">👤 Profile & Update</h3>
                    <ProfileForm profile={profile} fetchProfile={fetchProfile} />
                    
                    {profile.bmi && (
                        <div className="mt-4 pt-4 border-t border-gray-200">
                            <p className="mb-2 text-md font-bold text-gray-700">Health Metrics:</p>
                            <p><strong>BMI:</strong> {profile.bmi}</p>
                            <p><strong>BMR (Resting Cal):</strong> {profile.bmr}</p>
                            {profile.tdee && <p><strong>TDEE (Maintenance):</strong> {profile.tdee}</p>}
                            
                            <hr className="my-2 border-dashed" />
                            
                            <p className="font-bold text-blue-700">Goal Target:</p>
                            <p className="text-xl font-extrabold text-green-700">
                                {profile.dailyCalorieTarget} kcal/day
                            </p>
                            <p className="mt-2"><strong>Latest Risk:</strong> <span className={`font-bold text-${profile.latestRisk === 'High' ? 'red' : profile.latestRisk === 'Medium' ? 'orange' : 'green'}-600`}>{profile.latestRisk || 'N/A'}</span></p>
                        </div>
                    )}
                    
                    {/* Nutrient Warning Component */}
                    {/* The fetchProfile call here ensures the latest logged meals are available for the RDI check */}
                    <NutrientWarning fetchProfile={fetchProfile} /> 
                </div>

                {/* 2. Health Risk Check (Module 3) */}
                <div className="md:col-span-1 bg-white p-6 rounded-lg shadow-lg">
                    <h3 className="text-xl font-bold mb-4">❤️ Health Risk Check</h3>
                    {isProfileIncomplete ? (
                        <p className="text-red-500">Please complete Age, Height, Weight above to check risk.</p>
                    ) : (
                        <RiskForm profile={profile} fetchProfile={fetchProfile} />
                    )}
                </div>

                {/* 3. Image Upload (Module 2) */}
                <div className="md:col-span-1 bg-white p-6 rounded-lg shadow-lg">
                    <h3 className="text-xl font-bold mb-4">🥗 Calorie Estimation</h3>
                    <CalorieUpload />
                </div>
                
            </div>
            
            {/* 4. Analytics & Logs (Module 5) */}
            <div className="mt-8 bg-white p-6 rounded-lg shadow-lg">
                <h3 className="text-xl font-bold mb-4">📊 Daily Analytics & Progress</h3>
                <ProgressChart 
                    dailyCalorieTarget={profile.dailyCalorieTarget} 
                />
                <p className="text-gray-600 mt-4 text-sm">
                    The Risk Score Overlay (Y-axis: Left) visually shows how weight and calorie intake trended 
                    around periods of 'High' (3) or 'Low' (1) predicted health risk.
                </p>
            </div>
        </div>
    );
};

export default Dashboard;
